        \left[x^{j - 1}\coordvf{x^j}, x^\alpha\coordvf{x^i}\right] & = x^{j - 1}\f{\p x^\alpha}{\p x^j}\coordvf{x^i} - x^\alpha\f{\p x^{j - 1}}{\p x^i}\coordvf{x^j}.
    \end{align*}
